import{_ as l,y as n,a as i,o as d,a2 as a,D as o,g as r,I as t}from"./chunks/framework.DCcmcJcL.js";const k=JSON.parse('{"title":"Seller Users & Roles","description":"","frontmatter":{},"headers":[],"relativePath":"multi-vendor-marketplace/seller-user-role-management.md","filePath":"multi-vendor-marketplace/seller-user-role-management.md","lastUpdated":1782394364000}'),m={name:"multi-vendor-marketplace/seller-user-role-management.md"};function p(c,e,h,g,u,b){const s=n("ImagePopup");return d(),i("div",null,[e[0]||(e[0]=a('<h1 id="seller-users-roles" tabindex="-1">Seller Users &amp; Roles <a class="header-anchor" href="#seller-users-roles" aria-label="Permalink to &quot;Seller Users &amp; Roles&quot;">​</a></h1><p>Larger stores are rarely run by one person. The Multi Vendor Marketplace lets a seller add <strong>team members (users)</strong> to their store and control exactly what each member can do through <strong>roles</strong>. This keeps the store secure while letting sellers delegate day-to-day work.</p><p>Both screens live under the seller panel <strong>Settings</strong> menu.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><p>A role is a named set of permissions. Sellers create roles and assign them to their team members.</p><h3 id="create-a-role" tabindex="-1">Create a Role <a class="header-anchor" href="#create-a-role" aria-label="Permalink to &quot;Create a Role&quot;">​</a></h3><p>Go to <strong>Settings → Roles</strong> and click <strong>Create Role</strong>, then provide:</p><ul><li><p><strong>Name:</strong> A label for the role (e.g. <em>Catalog Manager</em>, <em>Order Staff</em>).</p></li><li><p><strong>Description:</strong> A short note describing what the role is for.</p></li><li><p><strong>Permission Type:</strong></p><ul><li><strong>All</strong> — the role can access every seller-panel section.</li><li><strong>Custom</strong> — pick exactly which sections the role may use from the permission tree (Products, Orders, Transactions, Settings, etc.). When you tick a permission, its parent sections are selected automatically so access stays consistent.</li></ul></li></ul><p>Click <strong>Save</strong> to create the role.</p>',9)),o(s,{src:"/images/multi-vendor-marketplace/seller-role-create.png",alt:"Create Seller Role"}),e[1]||(e[1]=a('<blockquote><p><strong>Tip:</strong> Use <strong>Custom</strong> roles to give staff only what they need — for example, a role that can manage products but cannot view transactions or change store settings.</p></blockquote><h3 id="edit-or-delete" tabindex="-1">Edit or Delete <a class="header-anchor" href="#edit-or-delete" aria-label="Permalink to &quot;Edit or Delete&quot;">​</a></h3><p>Sellers can update a role&#39;s permissions at any time, or delete a role that is no longer needed. Changing a role from <strong>All</strong> to <strong>Custom</strong> re-applies the newly selected permission set to everyone holding that role.</p><h2 id="users-team-members" tabindex="-1">Users (Team Members) <a class="header-anchor" href="#users-team-members" aria-label="Permalink to &quot;Users (Team Members)&quot;">​</a></h2><p>Users are the people who log in to the seller store. Each user is assigned a role that defines their access.</p><h3 id="add-a-user" tabindex="-1">Add a User <a class="header-anchor" href="#add-a-user" aria-label="Permalink to &quot;Add a User&quot;">​</a></h3><p>Go to <strong>Settings → Users</strong> and click <strong>Create User</strong>, then provide:</p><ul><li><p><strong>Name:</strong> The team member&#39;s name.</p></li><li><p><strong>Email:</strong> Their login email address (must be unique).</p></li><li><p><strong>Password / Confirm Password:</strong> Set the account password. (When editing an existing user, leaving the password blank keeps the current one.)</p></li><li><p><strong>Role:</strong> Choose one of the roles created above to control the user&#39;s access.</p></li><li><p><strong>Status:</strong> Enable or disable the account.</p></li></ul>',8)),o(s,{src:"/images/multi-vendor-marketplace/seller-user-create.png",alt:"Create Seller User"}),e[2]||(e[2]=r("p",null,[t("Click "),r("strong",null,"Save"),t(" to create the user. They can now sign in to the seller panel with the permissions granted by their role.")],-1)),e[3]||(e[3]=r("h3",{id:"edit-or-delete-1",tabindex:"-1"},[t("Edit or Delete "),r("a",{class:"header-anchor",href:"#edit-or-delete-1","aria-label":'Permalink to "Edit or Delete"'},"​")],-1)),e[4]||(e[4]=r("p",null,"Sellers can update a user's details, change their role, reset their password, or remove the user entirely.",-1)),e[5]||(e[5]=r("blockquote",null,[r("p",null,[r("strong",null,"Note:"),t(" The original seller account is the owner and always retains full access. Added users are sub-accounts whose access is limited by their assigned role.")])],-1))])}const S=l(m,[["render",p]]);export{k as __pageData,S as default};
